 13→func TestKiro_Info(t *testing.T) {
 14→	t.Parallel()
 15→	env := NewKiroTestEnv(t)
 16→
 17→	var resp struct {
 18→		ProtocolVersion int      `json:"protocol_version"`
 19→		Name            string   `json:"name"`
 20→		Type            string   `json:"type"`
 21→		Description     string   `json:"description"`
 22→		IsPreview       bool     `json:"is_preview"`
 23→		ProtectedDirs   []string `json:"protected_dirs"`
 24→		HookNames       []string `json:"hook_names"`
 25→		Capabilities    struct {
 26→			Hooks              bool `json:"hooks"`
 27→			TranscriptAnalyzer bool `json:"transcript_analyzer"`
 28→		} `json:"capabilities"`
 29→	}
 30→	env.Runner.RunJSON(t, &resp, "", "info")
 31→
 32→	if resp.ProtocolVersion != 1 {
 33→		t.Errorf("protocol_version = %d, want 1", resp.ProtocolVersion)
 34→	}
 35→	if resp.Name != "kiro" {
 36→		t.Errorf("name = %q, want %q", resp.Name, "kiro")
 37→	}
 38→	if resp.Type != "Kiro" {
 39→		t.Errorf("type = %q, want %q", resp.Type, "Kiro")
 40→	}
 41→	if !resp.Capabilities.Hooks {
 42→		t.Error("capabilities.hooks should be true")
 43→	}
 44→	if !resp.Capabilities.TranscriptAnalyzer {
 45→		t.Error("capabilities.transcript_analyzer should be true")
 46→	}
 47→	if len(resp.HookNames) != 5 {
 48→		t.Errorf("hook_names count = %d, want 5", len(resp.HookNames))
 49→	}
 50→	if len(resp.ProtectedDirs) != 1 || resp.ProtectedDirs[0] != ".kiro" {
 51→		t.Errorf("protected_dirs = %v, want [.kiro]", resp.ProtectedDirs)
 52→	}
 53→}
