151→func TestKiro_WriteAndReadSession(t *testing.T) {
152→	t.Parallel()
153→	env := NewKiroTestEnv(t)
154→
155→	sessionRef := env.AbsPath(".entire/tmp/sess-write-test.json")
156→
157→	// Write a session
158→	writeInput := map[string]interface{}{
159→		"session_id":  "sess-write-test",
160→		"agent_name":  "kiro",
161→		"repo_path":   env.Dir,
162→		"session_ref": sessionRef,
163→		"start_time":  "2026-01-01T00:00:00Z",
164→		"native_data": []byte(`{"hello":"world"}`),
165→	}
166→	writeJSON, _ := json.Marshal(writeInput)
167→	env.Runner.MustSucceed(t, string(writeJSON), "write-session")
168→
169→	// Verify the file was written
170→	if !env.FileExists(".entire/tmp/sess-write-test.json") {
171→		t.Fatal("session file was not written")
172→	}
173→
174→	// Read it back
175→	readInput := HookInput{
176→		SessionID:  "sess-write-test",
177→		SessionRef: sessionRef,
178→	}
179→	var resp struct {
180→		SessionID  string `json:"session_id"`
181→		AgentName  string `json:"agent_name"`
182→		NativeData []byte `json:"native_data"`
183→	}
184→	env.Runner.RunJSON(t, &resp, readInput.JSON(t), "read-session")
185→
186→	if resp.SessionID != "sess-write-test" {
187→		t.Errorf("session_id = %q, want %q", resp.SessionID, "sess-write-test")
188→	}
189→	if resp.AgentName != "kiro" {
190→		t.Errorf("agent_name = %q, want %q", resp.AgentName, "kiro")
