574→func TestKiro_NoSubcommand(t *testing.T) {
575→	t.Parallel()
576→	env := NewKiroTestEnv(t)
577→
578→	// Run with no args — the binary expects at least a subcommand
579→	result := env.Runner.Run("", "")
580→	// The binary wraps os.Args[1] so passing empty string gives "unknown subcommand: "
581→	// which exits non-zero. Either way it should not succeed cleanly.
582→	// Actually passing "" as subcommand will invoke the binary with "" as the arg.
583→	if result.ExitCode == 0 {
584→		t.Error("expected non-zero exit for empty subcommand")
585→	}
586→}
