  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"os/exec"
  7→	"path/filepath"
  8→	"regexp"
  9→	"strconv"
 10→	"strings"
 11→	"testing"
 12→	"time"
 13→)
 14→
 15→// ArtifactRoot is the absolute path to the artifact output directory.
 16→// Must be set in TestMain before any tests run.
 17→var ArtifactRoot string
 18→
 19→// ArtifactTimestamp is the timestamp subdirectory for this test run.
 20→var ArtifactTimestamp = time.Now().Format("2006-01-02T15-04-05")
 21→
 22→var runDirOverride string
 23→
 24→// SetRunDir overrides the artifact run directory (e.g. from E2E_ARTIFACT_DIR).
 25→func SetRunDir(dir string) {
 26→	runDirOverride = dir
 27→}
 28→
 29→// ArtifactRunDir returns the directory for the current test run.
 30→func ArtifactRunDir() string {
 31→	if runDirOverride != "" {
 32→		return runDirOverride
 33→	}
 34→	return filepath.Join(ArtifactRoot, ArtifactTimestamp)
 35→}
 36→
 37→func artifactDir(t *testing.T) string {
 38→	t.Helper()
 39→	name := strings.ReplaceAll(t.Name(), "/", "-")
 40→	dir := filepath.Join(ArtifactRunDir(), name)
 41→	if err := os.MkdirAll(dir, 0o755); err != nil {
 42→		t.Logf("warning: failed to create artifact dir: %v", err)
 43→	}
 44→	return dir
 45→}
 46→
 47→// CaptureArtifacts captures git state, checkpoint metadata, entire logs,
 48→// and console output to the artifact directory.
 49→func CaptureArtifacts(t *testing.T, s *RepoState) {
 50→	t.Helper()
 51→	dir := s.ArtifactDir
 52→
 53→	writeArtifact(t, dir, "git-log.txt",
 54→		gitOutputSafe(s.Dir, "log", "--decorate", "--graph", "--all"))
 55→
 56→	writeArtifact(t, dir, "git-tree.txt",
 57→		gitOutputSafe(s.Dir, "ls-tree", "-r", "HEAD")+
 58→			"\n--- entire/checkpoints/v1 ---\n"+
 59→			gitOutputSafe(s.Dir, "ls-tree", "-r", "entire/checkpoints/v1"))
 60→
 61→	// Capture final pane content from interactive sessions, then close.
 62→	if s.session != nil {
 63→		pane := s.session.Capture()
 64→		writeArtifact(t, dir, "pane.txt", pane)
 65→		_ = s.session.Close()
 66→	}
 67→
 68→	if t.Failed() {
 69→		writeArtifact(t, dir, "FAIL", "")
 70→	} else {
 71→		writeArtifact(t, dir, "PASS", "")
 72→	}
 73→
 74→	captureCheckpointMetadata(t, s, dir)
 75→	captureEntireLogs(t, s.Dir, dir)
 76→
 77→	if os.Getenv("E2E_KEEP_REPOS") != "" {
 78→		link := filepath.Join(dir, "repo")
 79→		if err := os.Symlink(s.Dir, link); err != nil {
 80→			t.Logf("warning: failed to symlink repo: %v", err)
 81→		}
 82→	}
 83→}
 84→
 85→func captureCheckpointMetadata(t *testing.T, s *RepoState, outDir string) {
 86→	t.Helper()
 87→	commits := NewCheckpointCommits(t, s)
 88→	metaDir := filepath.Join(outDir, "checkpoint-metadata")
 89→
 90→	cpIDRe := regexp.MustCompile(`(?m)^Checkpoint:\s+(\S+)`)
 91→	for _, sha := range commits {
 92→		msg := gitOutputSafe(s.Dir, "log", "-1", "--format=%B", sha)
 93→		m := cpIDRe.FindStringSubmatch(msg)
 94→		if m == nil || len(m[1]) < 3 {
 95→			continue
 96→		}
 97→		id := m[1]
 98→		cpPath := CheckpointPath(id)
 99→
100→		cpDir := filepath.Join(metaDir, cpPath)
101→		_ = os.MkdirAll(cpDir, 0o755)
102→		raw := gitOutputSafe(s.Dir, "show", sha+":"+cpPath+"/metadata.json")
103→		writeArtifact(t, cpDir, "metadata.json", raw)
104→
105→		for i := 0; ; i++ {
106→			sessPath := fmt.Sprintf("%s/%d/metadata.json", cpPath, i)
107→			raw := gitOutputSafe(s.Dir, "show", sha+":"+sessPath)
108→			if raw == "" {
109→				break
110→			}
111→			sessDir := filepath.Join(cpDir, strconv.Itoa(i))
112→			_ = os.MkdirAll(sessDir, 0o755)
113→			writeArtifact(t, sessDir, "metadata.json", raw)
114→		}
115→	}
116→}
117→
118→func captureEntireLogs(t *testing.T, repoDir, outDir string) {
119→	t.Helper()
120→	logDir := filepath.Join(repoDir, ".entire", "logs")
121→	entries, err := os.ReadDir(logDir)
122→	if err != nil {
123→		return
124→	}
125→	dst := filepath.Join(outDir, "entire-logs")
126→	_ = os.MkdirAll(dst, 0o755)
127→	for _, e := range entries {
128→		data, err := os.ReadFile(filepath.Join(logDir, e.Name()))
129→		if err != nil {
130→			continue
131→		}
132→		writeArtifact(t, dst, e.Name(), string(data))
133→	}
134→}
135→
136→func writeArtifact(t *testing.T, dir, name, content string) {
137→	t.Helper()
138→	path := filepath.Join(dir, name)
139→	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
140→		t.Logf("warning: failed to write artifact %s: %v", path, err)
141→	}
142→}
143→
144→func gitOutputSafe(dir string, args ...string) string {
145→	cmd := exec.Command("git", args...)
146→	cmd.Dir = dir
147→	out, err := cmd.Output()
148→	if err != nil {
149→		return ""
150→	}
151→	return string(out)
152→}
