 51→func (k *Kiro) Bootstrap() error {
 52→	// No-op locally. On CI, write config for non-interactive auth if needed.
 53→	return nil
 54→}
 55→
 56→func (k *Kiro) RunPrompt(ctx context.Context, dir string, prompt string, opts ...Option) (Output, error) {
 57→	cfg := &runConfig{}
 58→	for _, o := range opts {
 59→		o(cfg)
 60→	}
 61→
 62→	bin, err := exec.LookPath(k.Binary())
 63→	if err != nil {
 64→		return Output{}, fmt.Errorf("%s not in PATH: %w", k.Binary(), err)
 65→	}
 66→
 67→	args := []string{"chat", "--no-interactive", "--trust-all-tools", "--agent", "entire", prompt}
 68→	displayArgs := []string{"chat", "--no-interactive", "--trust-all-tools", "--agent", "entire", fmt.Sprintf("%q", prompt)}
 69→
 70→	env := filterEnv(os.Environ(), "ENTIRE_TEST_TTY")
 71→
 72→	cmd := exec.CommandContext(ctx, bin, args...)
 73→	cmd.Dir = dir
 74→	cmd.Env = env
 75→	cmd.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
 76→	cmd.Cancel = func() error {
 77→		return syscall.Kill(-cmd.Process.Pid, syscall.SIGKILL)
 78→	}
 79→	cmd.WaitDelay = 5 * time.Second
 80→
 81→	var stdout, stderr strings.Builder
 82→	cmd.Stdout = &stdout
 83→	cmd.Stderr = &stderr
 84→
 85→	err = cmd.Run()
 86→	exitCode := 0
 87→	if err != nil {
 88→		exitErr := &exec.ExitError{}
 89→		if errors.As(err, &exitErr) {
 90→			exitCode = exitErr.ExitCode()
 91→		} else {
 92→			exitCode = -1
 93→		}
 94→	}
 95→
 96→	return Output{
 97→		Command:  k.Binary() + " " + strings.Join(displayArgs, " "),
 98→		Stdout:   stdout.String(),
 99→		Stderr:   stderr.String(),
100→		ExitCode: exitCode,
101→	}, err
102→}
103→
104→func (k *Kiro) StartSession(ctx context.Context, dir string) (Session, error) {
105→	name := fmt.Sprintf("kiro-test-%d", time.Now().UnixNano())
106→
107→	s, err := NewTmuxSession(name, dir, []string{"ENTIRE_TEST_TTY"}, k.Binary(), "chat", "--agent", "entire")
108→	if err != nil {
109→		return nil, err
110→	}
111→
112→	// Wait for the initial prompt to appear.
113→	if _, err := s.WaitFor(k.PromptPattern(), 30*time.Second); err != nil {
114→		_ = s.Close()
115→		return nil, fmt.Errorf("waiting for initial prompt: %w", err)
116→	}
117→	s.stableAtSend = ""
118→
119→	return s, nil
120→}
